11	
12	CUTE_DEVICE void st_global_cs_128(float f0, float f1, float f2, float f3, void *dst_ptr) {
13	    asm volatile("st.weak.global.cs.v4.f32 [%0], {%1, %2, %3, %4};\n"
14	                 :
15	                 : "l"(dst_ptr),
16	                   "f"(f0), "f"(f1), "f"(f2), "f"(f3)
17	                );
18	}
19	
20	CUTE_DEVICE
21	float2 __shfl_xor_sync_float2(
22	    uint32_t mask, float2 value, int offset
23	) {
24	    float2 res;
25	    *reinterpret_cast<long long*>(&res) = __shfl_xor_sync(
26	        mask,
27	        *reinterpret_cast<long long*>(&value),
28	        offset
29	    );
30	    return res;
31	}
32	
33	CUTE_DEVICE
34	void tma_bulk_reduce_add(void const* src_ptr, void* dst_ptr, int32_t store_bytes) {
35	    uint32_t smem_int_ptr  = cast_smem_ptr_to_uint(src_ptr);
36	    asm volatile("cp.reduce.async.bulk.global.shared::cta.bulk_group.add.f32 [%0], [%1], %2;\n"
37	                     :
38	                     : "l"(dst_ptr), "r"(smem_int_ptr), "r"(store_bytes)
39	                     : "memory");
40	}
41	
42	template<int D_QK, bool HAVE_TOPK_LENGTH>
43	template<typename TMAParams>
44	__device__ void KernelTemplate<D_QK, HAVE_TOPK_LENGTH>::devfunc(const SparseAttnFwdParams &params, const TMAParams &tma_params) {
45	#if (defined(__CUDA_ARCH__) && (__CUDA_ARCH__ == 900)) || (defined(__CLION_IDE__) || defined(__VSCODE_IDE__))
46	    const int q_h_idx = blockIdx.x % (params.h_q/B_H);
47	    const int s_q_idx = blockIdx.x / (params.h_q/B_H);
48	    const int warpgroup_idx = cutlass::canonical_warp_group_idx();
49	    const int warp_idx = cutlass::canonical_warp_idx_sync();
50	    const int idx_in_warpgroup = threadIdx.x % 128;
51	
52	    // Define shared tensors
53	    extern __shared__ char wksp_buf[];
54	    SharedMemoryPlan &plan = *reinterpret_cast<SharedMemoryPlan*>(wksp_buf);
55	    Tensor sQ = make_tensor(make_smem_ptr(plan.q_o.q.data()), SmemLayoutQ{});
56	    Tensor sO = make_tensor(make_smem_ptr(plan.q_o.o.data()), SmemLayoutO{});
57	    Tensor sS0 = make_tensor(make_smem_ptr(D_QK == 576 ? plan.k[0].data()+64*512 : plan.s[1].data()), SmemLayoutS{});    // Overlap with sK0's RoPE part for V3.2
58	    Tensor sS1 = make_tensor(make_smem_ptr(plan.s[0].data()), SmemLayoutS{});
59	
60	    if (warp_idx == 0 && elect_one_sync()) {
61	        // Prefetch TMA descriptors
62	        cute::prefetch_tma_descriptor(tma_params.tma_Q.get_tma_descriptor());
63	        cute::prefetch_tma_descriptor(&tma_params.tensor_map_O);
64	
65	        // Initialize barriers
66	        plan.bar_q.init(1);
67	        CUTE_UNROLL
68	        for (int i = 0; i < 2; ++i) {
69	            plan.bar_k0_free[i].init(128);
70	            plan.bar_k0_ready[i].init(128);
71	            plan.bar_k1_free[i].init(128);
72	            plan.bar_k1_ready[i].init(128);
73	        }
74	        plan.bar_is_kv_valid_ready.init(16);
75	        fence_barrier_init();
76	    }
77	
78	    __syncthreads();
79	    
80	    const int topk_length = HAVE_TOPK_LENGTH ? __ldg(params.topk_length + s_q_idx) : params.topk;
81	    const int num_topk_blocks = HAVE_TOPK_LENGTH ? ku::ceil_div(topk_length, (int)B_TOPK) : (int)((unsigned int)params.topk/(unsigned int)B_TOPK);
82	
83	    if (warpgroup_idx == 0 || warpgroup_idx == 1) {
84	        cutlass::arch::warpgroup_reg_alloc<216>();
85	
86	        if (warp_idx == 0 && elect_one_sync()) {
87	            // Load Q
88	            Tensor gQ = flat_divide(
89	                tma_params.tma_Q.get_tma_tensor(tma_params.shape_Q)(_, _, s_q_idx),
90	                Tile<Int<B_H>, Int<D_Q>>{}
91	            )(_, _, q_h_idx, _0{});
92	            launch_tma_copy(tma_params.tma_Q, gQ, sQ, plan.bar_q, TMA::CacheHintSm90::EVICT_FIRST);
93	            plan.bar_q.arrive_and_expect_tx(B_H*D_Q*sizeof(bf16));
94	        }
95	
96	        float rM[2] = {MAX_INIT_VAL, MAX_INIT_VAL}; // Meaning: the `max_logits` used for O / rL calculation
97	        float rL[2] = {0.0f, 0.0f};
98	        Tensor rO = partition_fragment_C(TiledMMA_PV_LocalP{}, Shape<Int<B_H>, Int<D_V/2>>{});
99	        Tensor rP = partition_fragment_C(TiledMMA_QK{}, Shape<Int<B_H>, Int<B_TOPK>>{});
100	        Tensor rS = make_tensor<bf16>(partition_shape_A(TiledMMA_PV_LocalP{}, Shape<Int<B_H>, Int<B_TOPK>>{}));
101	        cute::fill(rO, 0.0f);
102	        
103	        // Wait for Q
104	        plan.bar_q.wait(0);
105	
106	        bool cur_bar_wait_phase = 0;
107	        
108	        struct Warpgroup0 {};
109	        struct Warpgroup1 {};
110	
111	        auto qkt_gemm_one_tile = [&](auto warpgroup_idx, int tile_idx, bool clear_accum) {
112	            constexpr bool IS_WG1 = std::is_same_v<decltype(warpgroup_idx), Warpgroup1>;
113	            TiledMMA tiled_mma_QK = TiledMMA_QK{};
114	            Tensor sQ_tile = flat_divide(sQ, Tile<Int<B_H>, Int<64>>{})(_, _, _0{}, tile_idx);
115	            Tensor sK_tile = make_tensor(make_smem_ptr(plan.k[(int)IS_WG1].data() + tile_idx*B_TOPK*64), SmemLayoutKTiles<1>{});
116	            gemm_ss(clear_accum, tiled_mma_QK, sQ_tile, sK_tile, rP, idx_in_warpgroup);
117	        };
118	
119	        auto mask_rP = [&](auto warpgroup_idx) {
120	            constexpr bool IS_WG1 = std::is_same_v<decltype(warpgroup_idx), Warpgroup1>;
121	            plan.bar_is_kv_valid_ready.wait(cur_bar_wait_phase);
122	            CUTE_UNROLL
123	            for (int row_idx = 0; row_idx < 2; ++row_idx) {
124	                CUTE_UNROLL
125	                for (int i = row_idx*2; i < size(rP); i += 4) {
126	                    int col = 8*(i/4) + (idx_in_warpgroup%4)*2;
127	                    if (!plan.is_kv_valid[IS_WG1][col]) rP(i) = -INFINITY;
128	                    if (!plan.is_kv_valid[IS_WG1][col+1]) rP(i+1) = -INFINITY;
129	                }
130	            }
131	        };
132	
133	        auto online_softmax_and_rescale_o = [&](auto warpgroup_idx) {
134	            plan.bar_is_kv_valid_ready.wait(cur_bar_wait_phase);
135	            constexpr bool IS_WG1 = std::is_same_v<decltype(warpgroup_idx), Warpgroup1>;
136	            const float scale = params.sm_scale_div_log2;
137	            float r_sM[2];
138	            if constexpr (IS_WG1) {
139	                *(float2*)r_sM = plan.sM[idx_in_warpgroup/4];
140	            }
141	            float new_maxs[2];
142	            CUTE_UNROLL
143	            for (int row_idx = 0; row_idx < 2; ++row_idx) {
144	                // Get rowwise max
145	                float cur_max = -INFINITY;
146	                CUTE_UNROLL
147	                for (int i = row_idx*2; i < size(rP); i += 4) {
148	                    cur_max = max(cur_max, max(rP(i), rP(i+1)));
149	                }
150	                cur_max = max(cur_max, __shfl_xor_sync(0xffffffff, cur_max, 1));
151	                cur_max = max(cur_max, __shfl_xor_sync(0xffffffff, cur_max, 2));
152	                cur_max *= scale;
153	
154	                // Get new max and scale
155	                // For WG1, old_max comes from sM (written by WG0); for WG0, old_max comes from rM (read by WG0 from sM in the last round)
156	                new_maxs[row_idx] = max(IS_WG1 ? r_sM[row_idx] : rM[row_idx], cur_max);
157	
158	                // Scale O
159	                float scale_for_o = exp2f(rM[row_idx]-new_maxs[row_idx]);
160	                CUTE_UNROLL
161	                for (int i = row_idx*2; i < size(rO); i += 4) {
162	                    rO(i) *= scale_for_o;
163	                    rO(i+1) *= scale_for_o;
164	                }
165	
166	                // Get rS
167	                float cur_sum = 0;
168	                CUTE_UNROLL
169	                for (int i = row_idx*2; i < size(rP); i += 4) {
170	                    rP(i) = exp2f(rP(i)*scale - new_maxs[row_idx]);
171	                    rP(i+1) = exp2f(rP(i+1)*scale - new_maxs[row_idx]);
172	                    rS(i) = (bf16)rP(i);
173	                    rS(i+1) = (bf16)rP(i+1);
174	                    cur_sum += rP(i) + rP(i+1);
175	                }
176	                rL[row_idx] = rL[row_idx]*scale_for_o + cur_sum;
177	            }
178	            __syncwarp();
179	            if (idx_in_warpgroup%4 == 0) {
180	                plan.sM[idx_in_warpgroup/4] = *(float2*)new_maxs;
181	            }
182	            rM[0] = new_maxs[0];
183	            rM[1] = new_maxs[1];
184	        };
185	
186	        auto reduce_L = [&]() {
187	            // Reduce L
188	            // For example, thread 0 reduces with thread 1, 2, and 3, as well as thread 128, 129, 130, and 131
189	            rL[0] += __shfl_xor_sync(0xffffffff, rL[0], 1);
190	            rL[0] += __shfl_xor_sync(0xffffffff, rL[0], 2);
191	            rL[1] += __shfl_xor_sync(0xffffffff, rL[1], 1);
192	            rL[1] += __shfl_xor_sync(0xffffffff, rL[1], 2);
193	            if (idx_in_warpgroup%4 == 0)
194	                plan.sL[threadIdx.x/4] = *(float2*)(rL);
195	            NamedBarrier::arrive_and_wait(256, NamedBarriers::sL_ready);
196	            float2 peer_L = plan.sL[(threadIdx.x/4)^32];
197	            rL[0] += peer_L.x;
198	            rL[1] += peer_L.y;
199	        };
200	
201	        auto store_O = [&]() {
202	            float scale_factors[2];
203	            CUTE_UNROLL
204	            for (int i = 0; i < 2; ++i) {
205	                float attn_sink = params.attn_sink == nullptr ? -CUDART_INF_F : params.attn_sink[q_h_idx*B_H + get_AorC_row_idx(i, idx_in_warpgroup)]*CUDART_L2E_F;
206	                scale_factors[i] = 1.0f / (rL[i] + exp2f(attn_sink - rM[i]));
207	                if (rL[i] == 0.0f)
208	                    scale_factors[i] = 0.0f;    // The output should be 0 whatever attn_sink is
209	            }
210	
211	            Tensor sO = make_tensor(make_smem_ptr(plan.q_o.o.data() + warpgroup_idx*B_H*(D_V/2)), SmemLayoutOTiles<4>{});
212	            bf16* stsm_addrs[4];
213	            int stsm_row = (idx_in_warpgroup/32)*16 + (idx_in_warpgroup%16);
214	            CUTE_UNROLL
215	            for (int i = 0; i < 64/16; ++i) {
216	                stsm_addrs[i] = &sO(stsm_row, (idx_in_warpgroup%32/16*8) + 16*i);
217	            }
218	            bool s2g_pred = warp_idx%4 == 0 && elect_one_sync();
219	
220	            warpgroup_wait<0>();
221	            CUTE_UNROLL
222	            for (int tile_idx = 0; tile_idx < (D_V/2)/64; tile_idx += 1) {
223	                // Convert
224	                constexpr int NUM_ELEMS_EACH_TILE = B_H*64 / 128;   // 64: tile size, 128: warpgroup size
225	                bf16 cur_rOb[NUM_ELEMS_EACH_TILE];
226	                CUTE_UNROLL
227	                for (int i = 0; i < NUM_ELEMS_EACH_TILE; ++i) {
228	                    cur_rOb[i] = (bf16)(rO(tile_idx*NUM_ELEMS_EACH_TILE + i) * scale_factors[i%4>=2]);
229	                }
230	                // R -> S
231	                CUTE_UNROLL
232	                for (int i = 0; i < 64/16; ++i) {
233	                    SM90_U32x4_STSM_N::copy(
234	                        *reinterpret_cast<uint32_t*>(cur_rOb + i*8 + 0),
235	                        *reinterpret_cast<uint32_t*>(cur_rOb + i*8 + 2),
236	                        *reinterpret_cast<uint32_t*>(cur_rOb + i*8 + 4),
237	                        *reinterpret_cast<uint32_t*>(cur_rOb + i*8 + 6),
238	                        *reinterpret_cast<uint128_t*>(stsm_addrs[i] + tile_idx*(B_H*64))
239	                    );
240	                }
241	                fence_view_async_shared();
242	                NamedBarrier::arrive_and_wait(128, warpgroup_idx ? NamedBarriers::warpgroup1_sync : NamedBarriers::warpgroup0_sync);
243	                // S -> G
244	                if (s2g_pred) {
245	                    int g_tile_idx = warpgroup_idx*4 + tile_idx;
246	                    SM90_TMA_STORE_3D::copy(
247	                        &tma_params.tensor_map_O,
248	                        plan.q_o.o.data() + g_tile_idx*(B_H*64),
249	                        g_tile_idx*64,
250	                        q_h_idx*B_H,
251	                        s_q_idx
252	                    );
253	                }
254	            }
255	            cute::tma_store_arrive();
256	        };
257	
258	
259	        if (warpgroup_idx == 0) {
260	            // Warpgroup 0
261	
262	            auto pipelined_wait_and_qkt_gemm_l = [&]() __attribute__((always_inline)) {
263	                plan.bar_k0_ready[0].wait(cur_bar_wait_phase);
264	                qkt_gemm_one_tile(Warpgroup0{}, 0, true);
265	                qkt_gemm_one_tile(Warpgroup0{}, 1, false);
266	                qkt_gemm_one_tile(Warpgroup0{}, 2, false);
267	                qkt_gemm_one_tile(Warpgroup0{}, 3, false);
268	                warpgroup_commit_batch();
269	            };
270	
271	            auto pipelined_wait_and_qkt_gemm_r = [&]() __attribute__((always_inline)) {
272	                plan.bar_k0_ready[1].wait(cur_bar_wait_phase);
273	                qkt_gemm_one_tile(Warpgroup0{}, 4, false);
274	                qkt_gemm_one_tile(Warpgroup0{}, 5, false);
275	                qkt_gemm_one_tile(Warpgroup0{}, 6, false);
276	                qkt_gemm_one_tile(Warpgroup0{}, 7, false);
277	                if constexpr (D_QK == 576) {
278	                    qkt_gemm_one_tile(Warpgroup0{}, 8, false);
279	                }
280	                warpgroup_commit_batch();
281	            };
282	
283	            auto scale_rS = [&](float scales[2]) {
284	                CUTE_UNROLL
285	                for (int row = 0; row < 2; ++row) {
286	                    CUTE_UNROLL
287	                    for (int i = row*2; i < size(rP); i += 4) {
288	                        rS(i) = (bf16)(rP(i) * scales[row]);
289	                        rS(i+1) = (bf16)(rP(i+1) * scales[row]);
290	                    }
291	                }
292	            };
293	
294	            auto rescale_rO = [&](float scales[2]) {
295	                CUTE_UNROLL
296	                for (int row = 0; row < 2; ++row) {
297	                    CUTE_UNROLL
298	                    for (int i = row*2; i < size(rO); i += 4) {
299	                        rO(i) *= scales[row];
300	                        rO(i+1) *= scales[row];
301	                    }
302	                    rL[row] *= scales[row];
303	                }
304	            };
305	            
306	            CUTE_NO_UNROLL
307	            for (int block_idx = 0; block_idx < num_topk_blocks; block_idx += 2) {
308	                Tensor sV0l = make_tensor(make_smem_ptr(plan.k[0].data()), SmemLayoutKTilesTransposed<4>{});
309	                Tensor sV1l = make_tensor(make_smem_ptr(plan.k[1].data()), SmemLayoutKTilesTransposed<4>{});
310	
311	                if (block_idx == 0) {
312	                    // NOTE: We put this code here to avoid register spilling
313	                    pipelined_wait_and_qkt_gemm_l();
314	                    pipelined_wait_and_qkt_gemm_r();
315	                    warpgroup_wait<0>();
316	                }
317	                
318	                // Online softmax, inform WG1
319	                mask_rP(Warpgroup0{});
320	                
321	                
322	                online_softmax_and_rescale_o(Warpgroup0{});
323	                NamedBarrier::arrive(256, NamedBarriers::wg0_bunch_0_ready);
324	
325	                // Issue rO0 += rS0 @ sV0l
326	                gemm_rs(false, TiledMMA_PV_LocalP{}, rS, sV0l, rO, idx_in_warpgroup);
327	                warpgroup_commit_batch();
328	
329	                // Mark V0L as free
330	                warpgroup_wait<0>();
331	                plan.bar_k0_free[0].arrive();
332	
333	                // Wait for new sM, scale rS, save, inform WG1
334	                NamedBarrier::arrive_and_wait(256, NamedBarriers::wg1_bunch_0_ready);
335	                float new_rM[2], scale_factors[2];
336	                *(float2*)new_rM = plan.sM[idx_in_warpgroup/4];
337	                CUTE_UNROLL
338	                for (int i = 0; i < 2; ++i) {
339	                    scale_factors[i] = exp2f(rM[i] - new_rM[i]);
340	                    rM[i] = new_rM[i];
341	                }
342	                scale_rS(scale_factors);
343	                save_rS_to_sS(rS, sS0, idx_in_warpgroup);
344	                fence_view_async_shared();
345	                NamedBarrier::arrive(256, NamedBarriers::wg0_s0_ready);
346	
347	                // Wait for sS1
348	                NamedBarrier::arrive_and_wait(256, NamedBarriers::wg1_s1_ready);
349	
350	                // Rescale rO0, Issue rO0 += sS1 @ sV1L
351	                rescale_rO(scale_factors);
352	                gemm_ss(false, TiledMMA_PV_RemoteP{}, sS1, sV1l, rO, idx_in_warpgroup);
353	                warpgroup_commit_batch();
354	
355	                cur_bar_wait_phase ^= 1;
356	
357	                if (block_idx+2 < num_topk_blocks) {
358	                    // Launch the next QK^T GEMM
359	                    pipelined_wait_and_qkt_gemm_l();
360	
361	                    // Mark V1L as free
362	                    warpgroup_wait<1>();
363	                    plan.bar_k1_free[0].arrive();
364	                    pipelined_wait_and_qkt_gemm_r();
365	
366	                    // Wait for rP0 = sQ @ sK0
367	                    warpgroup_wait<0>();
368	                } else {
369	                    // Mark V1L as free
370	                    warpgroup_wait<0>();
371	                    plan.bar_k1_free[0].arrive();
372	                }
373	            }
374	
375	            reduce_L();
376	            store_O();
377	        } else {
378	            // Warpgroup 1
379	
380	            auto pipelined_wait_and_qkt_gemm = [&]() __attribute__((always_inline)) {
381	                plan.bar_k1_ready[1].wait(cur_bar_wait_phase);
382	                qkt_gemm_one_tile(Warpgroup1{}, 4, true);
383	                qkt_gemm_one_tile(Warpgroup1{}, 5, false);
384	                qkt_gemm_one_tile(Warpgroup1{}, 6, false);
385	                qkt_gemm_one_tile(Warpgroup1{}, 7, false);
386	                if constexpr (D_QK == 576) {
387	                    qkt_gemm_one_tile(Warpgroup1{}, 8, false);
388	                }
389	                plan.bar_k1_ready[0].wait(cur_bar_wait_phase);
390	                qkt_gemm_one_tile(Warpgroup1{}, 0, false);
391	                qkt_gemm_one_tile(Warpgroup1{}, 1, false);
392	                qkt_gemm_one_tile(Warpgroup1{}, 2, false);
393	                qkt_gemm_one_tile(Warpgroup1{}, 3, false);
394	                warpgroup_commit_batch();
395	            };
396	            
397	            CUTE_NO_UNROLL
398	            for (int block_idx = 0; block_idx < num_topk_blocks; block_idx += 2) {
399	                Tensor sV0r = make_tensor(make_smem_ptr(plan.k[0].data()+64*256), SmemLayoutKTilesTransposed<4>{});
400	                Tensor sV1r = make_tensor(make_smem_ptr(plan.k[1].data()+64*256), SmemLayoutKTilesTransposed<4>{});
401	
402	                // Issue rP1 = sQ @ sK1, and wait
403	                pipelined_wait_and_qkt_gemm();
404	                warpgroup_wait<0>();
405	
406	                mask_rP(Warpgroup1{});
407	
408	
409	                // Wait for WG0 (for sM), online softmax, Notify WG0 (sM ready)
410	                NamedBarrier::arrive_and_wait(256, NamedBarriers::wg0_bunch_0_ready);
411	                online_softmax_and_rescale_o(Warpgroup1{});
412	                NamedBarrier::arrive(256, NamedBarriers::wg1_bunch_0_ready);
413	
414	
415	                // Issue rO1 += rS1 @ sV1R
416	                gemm_rs(false, TiledMMA_PV_LocalP{}, rS, sV1r, rO, idx_in_warpgroup);
417	                warpgroup_commit_batch();
418	                
419	                // Wait for WG0 (for sS0), Issue rO1 += rS0 @ sV0R
420	                save_rS_to_sS(rS, sS1, idx_in_warpgroup);   // Put it here is faster
421	                NamedBarrier::arrive_and_wait(256, NamedBarriers::wg0_s0_ready);
422	                gemm_ss(false, TiledMMA_PV_RemoteP{}, sS0, sV0r, rO, idx_in_warpgroup);
423	                warpgroup_commit_batch();
424	                
425	                // Save rS1, inform WG0
426	                fence_view_async_shared();
427	                NamedBarrier::arrive(256, NamedBarriers::wg1_s1_ready);
428	
429	                // Wait for GEMM, and inform that sV1R is free
430	                warpgroup_wait<1>();
431	                plan.bar_k1_free[1].arrive();
432	
433	                // Wait for GEMM, and inform that sV0R is free
434	                warpgroup_wait<0>();
435	                plan.bar_k0_free[1].arrive();
436	
437	                cur_bar_wait_phase ^= 1;
438	            }
439	
440	            reduce_L();
441	            store_O();
442	
443	            // Save lse
444	            if (idx_in_warpgroup%4 == 0) {
445	                for (int row = 0; row < 2; ++row) {
446	                    int real_row = get_AorC_row_idx(row, idx_in_warpgroup);
447	                    bool is_no_valid_tokens = rL[row] == 0.0f;
448	                    plan.final_max_logits[real_row] = is_no_valid_tokens ? -INFINITY : rM[row]*CUDART_LN2_F;
449	                    plan.final_lse[real_row] = is_no_valid_tokens ? +INFINITY : logf(rL[row]) + rM[row]*CUDART_LN2_F;
450	                }
451	                fence_view_async_shared();
452	            }
453	
454	            NamedBarrier::arrive_and_wait(128, NamedBarriers::warpgroup1_sync);
455	            if (idx_in_warpgroup == 0) {
456	                int g_offset = s_q_idx*params.h_q + q_h_idx*B_H;
457	                SM90_BULK_COPY_S2G::copy(plan.final_max_logits, params.max_logits + g_offset, B_H*sizeof(float));
458	                SM90_BULK_COPY_S2G::copy(plan.final_lse, params.lse + g_offset, B_H*sizeof(float));
459	                cute::tma_store_arrive();
460	            }
461	        }
462	    } else {
463	        // Producer warpgroup
464	        cutlass::arch::warpgroup_reg_dealloc<72>();
465	
466	        constexpr int GROUP_SIZE = 8, NUM_GROUPS = 128/GROUP_SIZE;
467	        constexpr int NUM_ROWS_PER_GROUP = B_TOPK / NUM_GROUPS;
468	        int idx_in_group = idx_in_warpgroup % GROUP_SIZE;
469	        int group_idx = idx_in_warpgroup / GROUP_SIZE;
470	        int* gIndices = params.indices + s_q_idx*params.stride_indices_s_q;   // [topk]
471	
472	        bf16* my_sKV_base = &(make_tensor(make_smem_ptr(plan.k[0].data()), SmemLayoutKTiles<1>{})(group_idx, idx_in_group*8));
473	        bf16* my_gKV_base = params.kv + idx_in_group*8;
474	        
475	        int64_t token_indices[2][NUM_ROWS_PER_GROUP];
476	        bool is_token_valid[2][NUM_ROWS_PER_GROUP];
477	        auto load_token_indices = [&](int block_idx) {
478	            CUTE_UNROLL
479	            for (int buf_idx = 0; buf_idx < 2; ++buf_idx) {
480	                CUTE_UNROLL
481	                for (int local_row = 0; local_row < NUM_ROWS_PER_GROUP; ++local_row) {
482	                    int offs = (block_idx+buf_idx)*B_TOPK + local_row*NUM_GROUPS + group_idx;
483	                    int t = __ldg(gIndices + offs);
484	                    token_indices[buf_idx][local_row] = t*(int64_t)params.stride_kv_s_kv;   // We mult it with params.stride_kv_s_kv here since it's faster
485	                    bool is_cur_token_valid = t >= 0 && t < params.s_kv;
486	                    if constexpr (HAVE_TOPK_LENGTH) {
487	                        is_cur_token_valid &= offs < topk_length;
488	                    }
489	                    is_token_valid[buf_idx][local_row] = is_cur_token_valid;
490	                }
491	            }
492	        };
493	        
494	        int64_t cache_policy = createpolicy_evict_last();
495	        auto copy_tiles = [&](int block_idx, int buf_idx, int tile_start, int tile_end) {
496	            // Copy some K/V tiles from global memory to shared memory
497	            // A tile has a shape of 64 (B_TOPK) x 64
498	            // `buf_idx` is the index of the shared memory buffer, 0 or 1
499	            // `tile_idx` is the index of the tile to load, from 0 to D_K/64-1 = 8
500	            CUTE_UNROLL
501	            for (int local_row = 0; local_row < NUM_ROWS_PER_GROUP; ++local_row) {
502	                int64_t token_index = token_indices[buf_idx][local_row];
503	                CUTE_UNROLL
504	                for (int tile_idx = tile_start; tile_idx < tile_end; ++tile_idx) {
505	                    cp_async_cacheglobal_l2_prefetch_256B(
506	                        my_gKV_base + token_index + tile_idx*64,
507	                        my_sKV_base + (buf_idx*B_TOPK*D_K + tile_idx*(B_TOPK*64) + local_row*NUM_GROUPS*64),
508	                        is_token_valid[buf_idx][local_row],
509	                        cache_policy
510	                    );
511	                }
512	            }
513	        };
514	
515	        auto commit_to_mbar = [&](transac_bar_t &bar) {
516	            cutlass::arch::cpasync_barrier_arrive_noinc((uint64_t*)(&bar));
517	        };
518	
519	        int cur_bar_wait_phase = 1;
520	
521	        CUTE_NO_UNROLL
522	        for (int block_idx = 0; block_idx < num_topk_blocks; block_idx += 2) {
523	            load_token_indices(block_idx);
524	
525	            // V0L
526	            plan.bar_k0_free[0].wait(cur_bar_wait_phase);
527	            copy_tiles(block_idx+0, 0, 0, 4);
528	            commit_to_mbar(plan.bar_k0_ready[0]);
529	
530	            // V1R
531	            plan.bar_k1_free[1].wait(cur_bar_wait_phase);
532	            copy_tiles(block_idx+1, 1, 4, D_K/64);
533	            commit_to_mbar(plan.bar_k1_ready[1]);
534	            
535	            // V0R
536	            plan.bar_k0_free[1].wait(cur_bar_wait_phase);
537	            copy_tiles(block_idx+0, 0, 4, D_K/64);
538	            commit_to_mbar(plan.bar_k0_ready[1]);
539	
540	            // V1L
541	            plan.bar_k1_free[0].wait(cur_bar_wait_phase);
542	            copy_tiles(block_idx+1, 1, 0, 4);
543	            commit_to_mbar(plan.bar_k1_ready[0]);
544	
545	            // Valid mask
546	            // NOTE: V1R's finish implies maskings of the last round have finished
547	            if (idx_in_group == 0) {
548	                CUTE_UNROLL
549	                for (int buf_idx = 0; buf_idx < 2; ++buf_idx)
550	                    CUTE_UNROLL
551	                    for (int local_row = 0; local_row < NUM_ROWS_PER_GROUP; ++local_row)
552	                        plan.is_kv_valid[buf_idx][local_row*NUM_GROUPS+group_idx] = is_token_valid[buf_idx][local_row];
553	                plan.bar_is_kv_valid_ready.arrive();
554	            }
555	
556	            cur_bar_wait_phase ^= 1;
557	        }
558	    }
559	
560	
561	#else
562	    if (cute::thread0()) {
563	        CUTE_INVALID_CONTROL_PATH("This kernel only supports sm90");
564	    }
565	#endif
566	}
