568	template<typename Kernel, typename TMAParams>
569	__global__ void __launch_bounds__(Kernel::NUM_THREADS, 1, 1)
570	sparse_attn_fwd_kernel(__grid_constant__ const SparseAttnFwdParams params, __grid_constant__ const TMAParams tma_params) {
571	    Kernel::devfunc(params, tma_params);
572	}
573	
574	template<int D_QK, bool HAVE_TOPK_LENGTH>
575	void KernelTemplate<D_QK, HAVE_TOPK_LENGTH>::run(const SparseAttnFwdParams &params) {
576	    KU_ASSERT(params.h_kv == 1);
577	    KU_ASSERT(params.topk % (2*B_TOPK) == 0);   // To save some boundry checkings
578	    KU_ASSERT(params.topk > 0);
579	    KU_ASSERT(params.h_q % B_H == 0);
580	
581	    auto shape_Q = make_shape(params.h_q, params.d_qk, params.s_q);
582	    auto tma_Q = cute::make_tma_copy(
583	        SM90_TMA_LOAD{},
584	        make_tensor(
585	            make_gmem_ptr((bf16*)params.q),
586	            make_layout(
587	                shape_Q,
588	                make_stride(params.stride_q_h_q, _1{}, params.stride_q_s_q)
589	            )
590	        ),
591	        SmemLayoutQ{}
592	    );
593	
594	    CUtensorMap tensor_map_O;
595	    {
596	        uint64_t size[3] = {D_V, (unsigned long)params.h_q, (unsigned long)params.s_q};
597	        uint64_t stride[2] = {D_V*sizeof(bf16), D_V*params.h_q*sizeof(bf16)};
598	        uint32_t box_size[3] = {64, B_H, 1};
599	        uint32_t elem_stride[3] = {1, 1, 1};
600	        CUresult res = CUTLASS_CUDA_DRIVER_WRAPPER_CALL(cuTensorMapEncodeTiled)(
601	            &tensor_map_O,
602	            CUtensorMapDataType::CU_TENSOR_MAP_DATA_TYPE_BFLOAT16,
603	            3,
604	            params.out,
605	            size,
606	            stride,
607	            box_size,
608	            elem_stride,
609	            CUtensorMapInterleave::CU_TENSOR_MAP_INTERLEAVE_NONE,
610	            CUtensorMapSwizzle::CU_TENSOR_MAP_SWIZZLE_128B,
611	            CUtensorMapL2promotion::CU_TENSOR_MAP_L2_PROMOTION_NONE,
612	            CUtensorMapFloatOOBfill::CU_TENSOR_MAP_FLOAT_OOB_FILL_NONE
613	        );
614	        KU_ASSERT(res == CUresult::CUDA_SUCCESS);
615	    }
616	
617	    TmaParams<
618	        decltype(shape_Q), decltype(tma_Q)
619	    > tma_params = {
620	        shape_Q, tma_Q,
621	        tensor_map_O
622	    };
623	    auto kernel = &sparse_attn_fwd_kernel<KernelTemplate<D_QK, HAVE_TOPK_LENGTH>, decltype(tma_params)>;
624	
625	    constexpr size_t smem_size = sizeof(SharedMemoryPlan);
626	    KU_CUDA_CHECK(cudaFuncSetAttribute(kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size));
627	
628	    cutlass::ClusterLaunchParams launch_params = {
629	        dim3((params.h_q/B_H)*params.s_q, 1, 1),    // NOTE: We put s_q on the first dim since it can be larger than 65536 (the maximum size of griddim.y and griddim.z)
630	        dim3(NUM_THREADS, 1, 1),
631	        dim3(1, 1, 1),
632	        smem_size,
633	        params.stream
634	    }; 
635	    cutlass::launch_kernel_on_cluster(
636	        launch_params, (void*)kernel, params, tma_params
637	    );
638	    KU_CHECK_KERNEL_LAUNCH();
639	}
